    27	        target_ip_ = UDP_SERVER_IP_BASIC;
    28	        target_port_ = UDP_SERVER_PORT;
    29	        local_port_ = UDP_CLIENT_PORT;
    30	        udp_.InitCmdData(cmd_);
    31	
    32	        private_nh_.param("control_rate_hz", control_rate_hz_, 500.0);
    33	        private_nh_.param("command_timeout", command_timeout_, 0.25);
    34	        private_nh_.param("max_forward_speed", max_forward_speed_, 0.25);
    35	        private_nh_.param("max_rotate_speed", max_rotate_speed_, 0.60);
    36	        private_nh_.param("body_height", body_height_, 0.0);
    37	        private_nh_.param("invert_yaw_sign", invert_yaw_sign_, true);
    38	        private_nh_.param("startup_stand_time", startup_stand_time_, 1.0);
    39	
    40	        cmd_sub_ = nh_.subscribe("/cmd_vel", 1, &BaseControllerNode::cmdCallback, this);
    41	        recv_thread_ = std::thread(&BaseControllerNode::recvLoop, this);
    42	        recv_thread_.detach();
    43	
    44	        last_cmd_time_ = ros::Time(0);
    45	        last_report_time_ = ros::Time(0);
    46	        start_time_ = ros::Time::now();
    47	        last_state_tick_ = 0;
    48	
    49	        ROS_INFO("base_controller_node configured:"
    50	                 " target_ip=%s target_port=%d local_port=%d control_rate=%.1fHz timeout=%.2fs",
    51	                 target_ip_.c_str(), target_port_, local_port_, control_rate_hz_, command_timeout_);
    52	    }
    53	
    54	    void spin()
    55	    {
    56	        ros::Rate rate(control_rate_hz_);
    57	        while (ros::ok()) {
    58	            udp_.GetRecv(state_);
    59	
    60	            ros::spinOnce();
    61	            updateCommandFromTwist();
    62	            udp_.SetSend(cmd_);
    63	            udp_.Send();
    64	            maybeReport();
    65	
    66	            rate.sleep();
    67	        }
    68	
    69	        stopRobot();
    70	    }
    71	
    72	private:
    73	    void recvLoop()
    74	    {
    75	        while (ros::ok()) {
    76	            udp_.Recv();
    77	            usleep(2000);
    78	        }
    79	    }
    80	
    81	    void cmdCallback(const geometry_msgs::Twist::ConstPtr& msg)
    82	    {
    83	        last_cmd_ = *msg;
    84	        last_cmd_time_ = ros::Time::now();
    85	    }
    86	
    87	    void updateCommandFromTwist()
    88	    {
    89	        const ros::Time now = ros::Time::now();
    90	
    91	        cmd_.forwardSpeed = 0.0f;
    92	        cmd_.sideSpeed = 0.0f;
    93	        cmd_.rotateSpeed = 0.0f;
    94	        cmd_.bodyHeight = body_height_;
    95	        cmd_.mode = 1;  // forced stand by default
    96	        cmd_.roll = 0.0f;
    97	        cmd_.pitch = 0.0f;
    98	        cmd_.yaw = 0.0f;
    99	
   100	        if ((now - start_time_).toSec() < startup_stand_time_) {
   101	            return;
   102	        }
   103	
   104	        if (!commandActive(now)) {
   105	            return;
   106	        }
   107	
   108	        const double forward = clamp(last_cmd_.linear.x, -max_forward_speed_, max_forward_speed_);
   109	        double rotate = clamp(last_cmd_.angular.z, -max_rotate_speed_, max_rotate_speed_);
   110	        if (invert_yaw_sign_) {
   111	            rotate = -rotate;
   112	        }
   113	
   114	        if (std::fabs(forward) < 1e-3 && std::fabs(rotate) < 1e-3) {
   115	            return;
   116	        }
   117	
   118	        cmd_.mode = 2;  // walk continuously
   119	        cmd_.forwardSpeed = static_cast<float>(forward);
   120	        cmd_.rotateSpeed = static_cast<float>(rotate);
   121	    }
   122	
   123	    bool commandActive(const ros::Time& now) const
   124	    {
   125	        if (last_cmd_time_.isZero()) {
   126	            return false;
   127	        }
   128	        return (now - last_cmd_time_).toSec() <= command_timeout_;
   129	    }
   130	
   131	    void maybeReport()
   132	    {
   133	        const ros::Time now = ros::Time::now();
   134	        if (!last_report_time_.isZero() && (now - last_report_time_).toSec() < 1.0) {
   135	            return;
   136	        }
   137	        last_report_time_ = now;
   138	
   139	        if (state_.tick == last_state_tick_) {
   140	            ROS_WARN("base_controller_node state tick is not changing (tick=%u). Check Unitree UDP link to %s:%d.",
   141	                     state_.tick, target_ip_.c_str(), target_port_);
   142	        } else {
   143	            ROS_INFO("base_controller_node send(mode=%u fwd=%.3f rot=%.3f) recv(mode=%u fwd=%.3f tick=%u)",
   144	                     static_cast<unsigned int>(cmd_.mode),
   145	                     cmd_.forwardSpeed,
   146	                     cmd_.rotateSpeed,
   147	                     static_cast<unsigned int>(state_.mode),
   148	                     state_.forwardSpeed,
   149	                     state_.tick);
   150	        }
   151	
   152	        last_state_tick_ = state_.tick;
   153	    }
   154	
   155	    void stopRobot()
   156	    {
   157	        cmd_.mode = 1;
   158	        cmd_.forwardSpeed = 0.0f;
   159	        cmd_.sideSpeed = 0.0f;
   160	        cmd_.rotateSpeed = 0.0f;
   161	        cmd_.bodyHeight = body_height_;
   162	        cmd_.roll = 0.0f;
   163	        cmd_.pitch = 0.0f;
   164	        cmd_.yaw = 0.0f;
   165	
   166	        for (int i = 0; i < 20; ++i) {
   167	            udp_.SetSend(cmd_);
   168	            udp_.Send();
   169	            usleep(2000);
   170	        }
   171	    }
   172	
   173	    static double clamp(double value, double lower, double upper)
   174	    {
   175	        return std::max(lower, std::min(value, upper));
   176	    }
   177	
   178	    ros::NodeHandle nh_;
   179	    ros::NodeHandle private_nh_;
   180	    ros::Subscriber cmd_sub_;
   181	    std::thread recv_thread_;
   182	
   183	    UDP udp_;
   184	    HighCmd cmd_ = {0};
   185	    HighState state_ = {0};
   186	    geometry_msgs::Twist last_cmd_;
   187	
   188	    ros::Time start_time_;
   189	    ros::Time last_cmd_time_;
   190	    ros::Time last_report_time_;
   191	
   192	    std::string target_ip_;
   193	    int local_port_ = 8081;
   194	    int target_port_ = UDP_SERVER_PORT;
   195	    double control_rate_hz_ = 500.0;
   196	    double command_timeout_ = 0.25;
   197	    double max_forward_speed_ = 0.25;
   198	    double max_rotate_speed_ = 0.60;
   199	    double body_height_ = 0.0;
   200	    double startup_stand_time_ = 1.0;
   201	    bool invert_yaw_sign_ = true;
   202	    uint32_t last_state_tick_ = 0;
   203	};
   204	
   205	int main(int argc, char* argv[])
   206	{
   207	    ros::init(argc, argv, "base_controller_node");
   208	    BaseControllerNode node;
   209	    node.spin();
   210	    return 0;
   211	}
